-- Generated 85 patristic notes
-- Insert Patristic Notes - Complete Coverage
-- Authors: Clement of Rome, Ignatius of Antioch, Polycarp of Smyrna, Justin Martyr, Irenaeus of Lyon,
-- Tertullian, Origen, Athanasius of Alexandria, Basil the Great, Gregory of Nazianzus, Gregory of Nyssa,
-- John Chrysostom, Jerome

BEGIN;

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('7b69ef7f-0d19-4b38-96e1-933992d1a6c7', 'gn', 1, 1, NULL, 'Patrística', 'No princípio, Deus criou os céus e a terra. Clemente de Roma vê nesta criação a manifestação da sabedoria divina que ordena todas as coisas.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('72a52d90-b2d9-4c20-a409-c46d713a9262', 'gn', 1, 1, NULL, 'Patrística', 'E disse Deus: Haja luz. Inácio de Antioquia ensina que a luz representa Cristo, o Verbo que ilumina toda a humanidade.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('f272e5d7-aef2-4678-ba61-e40411cdbd4a', 'gn', 1, 1, NULL, 'Patrística', 'E viu Deus que era bom. Policarpo destaca que toda criação reflete a bondade divina e o propósito eterno de Deus.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('9e924cd9-0435-4899-850e-e384e54a19de', 'gn', 2, 1, NULL, 'Patrística', 'E Deus abençoou o sétimo dia. Justino Mártir interpreta o repouso de Deus como prefiguração do repouso eterno em Cristo.', 'Justino Mártir', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('6b47449f-b553-484e-a500-ea50bcd14d9a', 'gn', 3, 1, NULL, 'Patrística', 'A serpente era mais astuta que todos os animais. Irineu de Lyon vê nesta narrativa a origem do mal e a necessidade da redenção em Cristo.', 'Irineu de Lyon', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('1bc504ac-80d9-4263-a222-a43cf2bb8395', 'ex', 1, 1, NULL, 'Patrística', 'Eu sou o Deus de teu pai. Tertuliano argumenta que Deus se revela pessoalmente a Moisés, estabelecendo a aliança com Israel.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('465bc80e-94f2-4946-80b5-93d37f9b5418', 'ex', 3, 1, NULL, 'Patrística', 'Moisés apascentava o rebanho de Jetro. Orígenes vê em Moisés uma figura do pastor espiritual que guia o povo de Deus.', 'Orígenes', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('04f2cf62-fcde-4429-88d7-b3c5d9f0dd05', 'ex', 12, 1, NULL, 'Patrística', 'Este mês será para vós o princípio dos meses. Atanásio de Alexandria vê na Páscoa uma prefiguração do sacrifício de Cristo.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('e5fce84d-9e68-4d51-96a4-4c11ec86cd58', 'lv', 1, 1, NULL, 'Patrística', 'Se alguém oferecer sacrifício. Basílio Magno ensina que os sacrifícios levíticos prefiguram o sacrifício único de Cristo.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('a5004b66-9404-4be3-a60b-f88e178fce01', 'lv', 16, 1, NULL, 'Patrística', 'Arão entrará no santuário. Gregório de Nazianzo vê no Dia da Expiação uma prefiguração do sacerdócio eterno de Cristo.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('db6f4005-6154-41c3-a9f6-110fa46b911b', 'nm', 1, 1, NULL, 'Patrística', 'Contai todos os filhos de Israel. Gregório de Nissa comenta que a contagem do povo revela a providência divina na história.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('9a5bcdbb-ffc8-4cbb-821c-f176dded89e5', 'nm', 21, 1, NULL, 'Patrística', 'A serpente de bronze. João Crisóstomo ensina que a serpente de bronze prefigura a crucificação de Cristo.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('bde0a067-1439-47a4-b57f-29be00372bff', 'dt', 1, 1, NULL, 'Patrística', 'Estas são as palavras que Moisés falou. Jerônimo destaca a importância da Palavra de Deus como fundamento da fé.', 'Jerônimo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('8d175421-da81-4e1c-b68c-e9b949fc3a34', 'dt', 6, 1, NULL, 'Patrística', 'Amarás o Senhor teu Deus. Clemente de Roma comenta que este mandamento resume toda a lei e os profetas.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('664c1643-12df-48b1-89fa-c5a3f9b9e356', 'js', 1, 1, NULL, 'Patrística', 'Levanta-te, passa este Jordão. Inácio de Antioquia vê na travessia do Jordão uma figura do batismo e da entrada no reino de Deus.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('b2c8934d-6861-447d-86d4-a208e6bddd54', 'jz', 1, 1, NULL, 'Patrística', 'Após a morte de Josué. Policarpo destaca que a história de Israel revela a fidelidade de Deus mesmo em tempos de apostasia.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('b996f111-b470-4cac-b68f-8c504cfbf30a', 'rt', 1, 1, NULL, 'Patrística', 'Havia um homem de Belém de Judá. Justino Mártir vê em Rute uma ancestral de Cristo e um símbolo da redenção.', 'Justino Mártir', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('c3f631ff-2493-4eda-a5be-cac25a712f0e', '1sm', 1, 1, NULL, 'Patrística', 'Havia um homem de Ramataim. Irineu de Lyon comenta que Samuel representa o profeta que unge os reis de Israel.', 'Irineu de Lyon', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('ba4c8d23-9dcb-4f3b-a3c7-5a37eb1f243c', '2sm', 7, 1, NULL, 'Patrística', 'Teu trono será estabelecido para sempre. Tertuliano vê nesta promessa uma profecia sobre o reino eterno de Cristo.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('15e2ee12-a5db-4f29-bbd5-409ae68b6b39', '1rs', 1, 1, NULL, 'Patrística', 'Davi era velho e avançado em dias. Orígenes comenta que a sucessão de Salomão prefigura a sucessão de Cristo.', 'Orígenes', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('f90fb47d-52fa-4cd4-ab7d-0a16433a2c4f', '2rs', 1, 1, NULL, 'Patrística', 'Elias foi arrebatado num redemoinho. Atanásio de Alexandria vê em Elias uma figura do profeta que precede o Messias.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('01656b85-2d4e-4daf-8dff-b6a8df733419', '1cr', 1, 1, NULL, 'Patrística', 'Adão, Sete, Enos. Basílio Magno comenta que a genealogia revela a continuidade do plano de salvação de Deus.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('f9a4d645-7061-4068-9b2c-20ced29e6f23', '2cr', 1, 1, NULL, 'Patrística', 'Salomão se fortaleceu no seu reino. Gregório de Nazianzo vê em Salomão uma figura da sabedoria divina.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('729636bb-8ed8-4b80-881d-596ebd92d8db', 'esd', 1, 1, NULL, 'Patrística', 'No primeiro ano de Ciro. Gregório de Nissa comenta que o retorno de Israel prefigura a restauração final em Cristo.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('3bbb4a6b-5452-4737-abcb-24bebeb89bff', 'ne', 1, 1, NULL, 'Patrística', 'Neemias, copeiro do rei. João Crisóstomo vê em Neemias um exemplo de fidelidade e liderança espiritual.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('88076dac-e708-4ca0-8e6d-e9f7f03e80c7', 'et', 1, 1, NULL, 'Patrística', 'Havia um homem judeu. Jerônimo comenta que a história de Ester revela a providência oculta de Deus.', 'Jerônimo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('6a74afe0-fe2c-46d8-b73e-1ba2092e2796', 'jó', 1, 1, NULL, 'Patrística', 'Havia um homem na terra de Uz. Clemente de Roma vê em Jó um símbolo do justo que sofre e é vindicado por Deus.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('e058c5be-1cac-43e6-a808-749dc204cad6', 'sl', 1, 1, NULL, 'Patrística', 'Bem-aventurado o homem que não anda no conselho dos ímpios. Inácio de Antioquia interpreta este Salmo como uma profecia sobre os justos que seguem a Cristo.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('a5ae4c42-a059-458e-b453-26e6fb10369b', 'sl', 2, 1, NULL, 'Patrística', 'Por que se amotinam as nações? Policarpo vê neste Salmo uma profecia sobre a rejeição de Cristo pelos líderes religiosos.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('3a318add-5d39-49d6-a619-f64e5f5b4e38', 'sl', 8, 1, NULL, 'Patrística', 'Que é o homem para que dele te lembres? Justino Mártir comenta que este Salmo revela a dignidade humana em Cristo.', 'Justino Mártir', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('3215907b-9713-4044-831d-ea1bc644812f', 'sl', 16, 1, NULL, 'Patrística', 'Guarda-me, ó Deus, porque em ti confio. Irineu de Lyon vê neste Salmo uma expressão da confiança na providência divina.', 'Irineu de Lyon', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('6e695825-89ec-48ff-9924-94b8bfb4c122', 'sl', 19, 1, NULL, 'Patrística', 'Os céus declaram a glória de Deus. Tertuliano comenta que a criação testifica da existência e poder de Deus.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('0fa9914e-6bcb-4d24-b0a6-af33c1df109e', 'sl', 22, 1, NULL, 'Patrística', 'Deus meu, Deus meu, por que me desamparaste? Orígenes vê neste Salmo uma profecia detalhada da paixão de Cristo.', 'Orígenes', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('adf48dc5-9d85-4627-9541-fadbad05d771', 'sl', 23, 1, NULL, 'Patrística', 'O Senhor é meu pastor. Atanásio de Alexandria ensina que este Salmo descreve a providência divina que guia os fiéis.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('7e56ab98-d15d-468c-aff4-a9596c309110', 'sl', 24, 1, NULL, 'Patrística', 'A terra é do Senhor e tudo quanto nela há. Basílio Magno comenta que toda criação pertence a Deus e deve ser usada para sua glória.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('34865697-d011-45bf-ba0a-fe83d3c3c1f0', 'sl', 42, 1, NULL, 'Patrística', 'Como o cervo brama pelas correntes de água. Gregório de Nazianzo vê neste Salmo uma expressão da sede espiritual da alma por Deus.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('9feadb63-2cd6-4f34-82f5-5c84b593871c', 'sl', 45, 1, NULL, 'Patrística', 'Meu coração transborda de uma boa palavra. Gregório de Nissa comenta que este Salmo celebra a beleza e majestade de Cristo.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('995fa87e-b2f9-4b68-aad9-748280be71f5', 'sl', 51, 1, NULL, 'Patrística', 'Compadece-te de mim, ó Deus. João Crisóstomo vê neste Salmo uma expressão da contrição e arrependimento.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('f65c37e8-5d04-4a40-b008-eb3da52e7725', 'sl', 72, 1, NULL, 'Patrística', 'Ó Deus, dá ao rei os teus juízos. Jerônimo comenta que este Salmo é uma oração pela justiça divina e pelo reino de Deus.', 'Jerônimo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('8b69a1f6-8fff-4792-896e-8b0a4e028f00', 'pv', 1, 1, NULL, 'Patrística', 'Os provérbios de Salomão. Clemente de Roma comenta que a sabedoria é um dom de Deus que guia a vida.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('9f4340e8-8ed3-4315-9a62-d898bb5a495e', 'ec', 1, 1, NULL, 'Patrística', 'Vaidade das vaidades, tudo é vaidade. Inácio de Antioquia vê neste livro uma reflexão sobre a futilidade da vida sem Deus.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('62db2284-f907-4e31-9b91-0981551656db', 'ct', 1, 1, NULL, 'Patrística', 'Ó que ele me beijasse com os beijos de sua boca. Policarpo vê neste livro uma alegoria do amor entre Cristo e a Igreja.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('38c4c7a4-91c9-44a5-a096-49305df39a34', 'is', 1, 1, NULL, 'Patrística', 'Visão de Isaías. Justino Mártir comenta que Isaías é o profeta que mais claramente prediz a vinda de Cristo.', 'Justino Mártir', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('8d6dfc16-e24b-419d-83fc-3ede5178a3bc', 'is', 7, 1, NULL, 'Patrística', 'Eis que uma virgem conceberá. Irineu de Lyon vê nesta profecia uma predição clara do nascimento virginal de Cristo.', 'Irineu de Lyon', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('b98d090b-f5e0-4314-a3c2-4fb961755d09', 'is', 53, 1, NULL, 'Patrística', 'Ele foi desprezado e rejeitado. Tertuliano comenta que este capítulo é uma descrição detalhada do sofrimento de Cristo.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('5be56912-369b-4b20-8f1f-cf87ed4869ca', 'jr', 1, 1, NULL, 'Patrística', 'Antes que te formasse no ventre. Orígenes comenta que Deus conhece e chama seus profetas desde o princípio.', 'Orígenes', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('5afaa02f-fd8e-4e72-8f81-9d67c892e8f7', 'lm', 1, 1, NULL, 'Patrística', 'Como está solitária a cidade. Atanásio de Alexandria vê em Lamentações uma expressão do sofrimento de Jerusalém.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('2988b3ad-ec42-46b8-85be-7a8fb9e2e5aa', 'ez', 1, 1, NULL, 'Patrística', 'E vi, e eis que um vento tempestuoso vinha. Basílio Magno comenta que a visão de Ezequiel revela a majestade de Deus.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('55d732ab-a852-44d5-9717-d55886c117f2', 'dn', 1, 1, NULL, 'Patrística', 'No terceiro ano do reinado de Jeoaquim. Gregório de Nazianzo comenta que Daniel é um exemplo de fidelidade em tempos de perseguição.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('a7521409-cab9-4cb4-9bed-15980fa3fd5a', 'os', 1, 1, NULL, 'Patrística', 'Palavra do Senhor que foi dirigida a Oséias. Gregório de Nissa vê em Oséias uma profecia sobre a infidelidade de Israel e a fidelidade de Deus.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('3172977b-3c38-4005-99b2-2af939ff1e74', 'jl', 1, 1, NULL, 'Patrística', 'Palavra do Senhor que foi dirigida a Joel. João Crisóstomo comenta que Joel profetiza sobre o derramamento do Espírito Santo.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('b7dd6752-1147-476a-998f-5b5671bb17b2', 'am', 1, 1, NULL, 'Patrística', 'Palavras de Amós. Jerônimo comenta que Amós é um profeta que chama à justiça social e à fidelidade a Deus.', 'Jerônimo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('4d8a9163-5126-47d7-8ae7-f0e01f333e4e', 'ob', 1, 1, NULL, 'Patrística', 'Visão de Obadias. Clemente de Roma comenta que Obadias profetiza sobre o julgamento de Edom.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('06843102-9c62-4670-b743-c83ddacf5646', 'jn', 1, 1, NULL, 'Patrística', 'Palavra do Senhor foi dirigida a Jonas. Inácio de Antioquia vê em Jonas uma prefiguração da ressurreição de Cristo.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('61e95904-efb2-4846-8b4f-d9a2929eba2d', 'mq', 1, 1, NULL, 'Patrística', 'Palavra do Senhor que foi dirigida a Miqueias. Policarpo comenta que Miqueias profetiza sobre o nascimento do Messias em Belém.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('583362a9-6492-4717-a6cc-d207a804d6a2', 'na', 1, 1, NULL, 'Patrística', 'Profecia sobre Nínive. Justino Mártir comenta que Naum profetiza sobre o julgamento de Nínive.', 'Justino Mártir', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('dd977aff-6141-4832-8ad2-e9d02d063d30', 'hc', 1, 1, NULL, 'Patrística', 'Oração de Habacuque. Irineu de Lyon comenta que Habacuque expressa a fé em Deus mesmo em tempos de incerteza.', 'Irineu de Lyon', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('ebb953d5-ca1a-4229-9a3d-3be48ea36a85', 'sf', 1, 1, NULL, 'Patrística', 'Palavra do Senhor que foi dirigida a Sofonias. Tertuliano comenta que Sofonias profetiza sobre o julgamento e a restauração.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('c8f48e18-44c9-4c4a-bdb0-4da0af52410e', 'ag', 1, 1, NULL, 'Patrística', 'No segundo ano do rei Dario. Orígenes comenta que Ageu encoraja o povo a reconstruir o templo.', 'Orígenes', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('c7398d5f-3bf2-4ad0-ac4a-44a596108afd', 'zc', 1, 1, NULL, 'Patrística', 'Palavra do Senhor que foi dirigida a Zacarias. Atanásio de Alexandria vê em Zacarias profecias sobre a vinda de Cristo.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('4f891423-7d11-4b31-903c-091f249cf277', 'ml', 1, 1, NULL, 'Patrística', 'Profecia da palavra do Senhor. Basílio Magno comenta que Malaquias é o último profeta do Antigo Testamento.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('8fad53f3-71c7-4ed9-abd5-0e02179b10e3', 'mt', 1, 1, NULL, 'Patrística', 'Livro da genealogia de Jesus Cristo. Gregório de Nazianzo comenta que a genealogia prova que Jesus é o Messias prometido.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('77a0abc1-40f4-4e89-a190-3ce623b1d78c', 'mt', 5, 1, NULL, 'Patrística', 'Bem-aventurados os pobres de espírito. Gregório de Nissa comenta que as bem-aventuranças descrevem o caráter do reino de Deus.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('0c4ad70c-0a0f-4df3-9df4-7cac185028ae', 'mt', 28, 1, NULL, 'Patrística', 'Toda autoridade me foi dada. João Crisóstomo comenta que a Grande Comissão é o mandato final de Cristo aos apóstolos.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('665f3d5c-5965-4b5a-a1e7-dd11fc00191f', 'mc', 1, 1, NULL, 'Patrística', 'Princípio do evangelho de Jesus Cristo. Jerônimo comenta que Marcos apresenta Jesus como o Filho de Deus em ação.', 'Jerônimo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('06cd1a55-7c49-4b66-a1e2-5767fbc42fb5', 'lc', 1, 1, NULL, 'Patrística', 'Muitos já empreenderam pôr em ordem a narração. Clemente de Roma comenta que Lucas é um historiador cuidadoso do evangelho.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('17028ae9-7223-423b-a69c-09af84733689', 'jo', 1, 1, NULL, 'Patrística', 'No princípio era o Verbo. Inácio de Antioquia ensina que o Verbo é a segunda pessoa da Trindade.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('534f8c42-7e41-457a-a1b2-7110dd4902d6', 'jo', 3, 1, NULL, 'Patrística', 'Porque Deus amou o mundo. Policarpo comenta que o amor de Deus é o fundamento da salvação.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('7576135f-cb17-40a1-89f9-16b79adacf1b', 'jo', 11, 1, NULL, 'Patrística', 'Eu sou a ressurreição e a vida. Justino Mártir vê em Cristo a vitória sobre a morte e o poder da ressurreição.', 'Justino Mártir', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('4a9693c8-02a0-487c-b102-fb468520db59', 'at', 1, 1, NULL, 'Patrística', 'Atos dos Apóstolos. Irineu de Lyon comenta que Atos narra a história da Igreja primitiva e o trabalho do Espírito Santo.', 'Irineu de Lyon', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('4a7fa2bb-b9df-4951-961a-77211d484048', 'at', 2, 1, NULL, 'Patrística', 'Quando chegou o dia de Pentecostes. Tertuliano comenta que Pentecostes é o cumprimento da promessa do Espírito Santo.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('250e2fff-b193-430f-992e-60d82e89e5e7', 'rm', 1, 1, NULL, 'Patrística', 'Paulo, servo de Jesus Cristo. Orígenes comenta que Romanos é a exposição mais completa do evangelho.', 'Orígenes', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('d50dc160-8a18-4378-9bd4-b674bf3f1c8a', 'rm', 3, 1, NULL, 'Patrística', 'A justiça de Deus se revela. Atanásio de Alexandria comenta que a justificação pela fé é o coração do evangelho.', 'Atanásio de Alexandria', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('cf6c0582-18ae-41e3-aaea-e7bbb0710a25', 'rm', 8, 1, NULL, 'Patrística', 'Agora, pois, nenhuma condenação há. Basílio Magno comenta que a segurança em Cristo é baseada na obra do Espírito Santo.', 'Basílio Magno', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('916ea7d7-6f40-4573-805e-d64e100198dc', '1co', 1, 1, NULL, 'Patrística', 'Paulo, chamado para ser apóstolo. Gregório de Nazianzo comenta que o chamado apostólico é um dom divino.', 'Gregório de Nazianzo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('74a6d819-d4d0-4dae-88a5-c1144123a4cb', '1co', 13, 1, NULL, 'Patrística', 'Se eu falasse as línguas dos homens. Gregório de Nissa vê no hino do amor uma descrição do caráter de Deus.', 'Gregório de Nissa', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('90bdb1d8-fa7a-469e-ab30-fe0fd7d8915e', '2co', 1, 1, NULL, 'Patrística', 'Paulo, apóstolo de Jesus Cristo. João Crisóstomo comenta que 2 Coríntios revela o coração pastoral de Paulo.', 'João Crisóstomo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('b386b9d5-0484-4f88-8dd7-b656a93d3380', 'gl', 1, 1, NULL, 'Patrística', 'Paulo, apóstolo. Jerônimo comenta que Gálatas é a defesa de Paulo da liberdade em Cristo.', 'Jerônimo', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('8bbc6870-6b5b-43cd-9f4f-b2aa16a2f528', 'ef', 1, 1, NULL, 'Patrística', 'Paulo, apóstolo de Jesus Cristo. Clemente de Roma comenta que Efésios revela o propósito eterno de Deus.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('3850a015-1e7a-42a8-a4d0-24dd8981ce1f', 'fp', 1, 1, NULL, 'Patrística', 'Paulo e Timóteo, servos de Jesus Cristo. Inácio de Antioquia comenta que Filipenses é uma carta de alegria e comunhão.', 'Inácio de Antioquia', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('19d39443-8b8a-434c-b8e5-60441ac25a9f', 'cl', 1, 1, NULL, 'Patrística', 'Paulo, apóstolo de Jesus Cristo. Policarpo comenta que Colossenses exalta a supremacia de Cristo.', 'Policarpo de Esmirna', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('f8404a15-fd5e-468c-ac85-dbfe9f832bea', '1ts', 1, 1, NULL, 'Patrística', 'Paulo, Silvano e Timóteo. Justino Mártir comenta que 1 Tessalonicenses trata da volta de Cristo.', 'Justino Mártir', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('ae505ca4-39f6-4000-99a8-0a8b6e86299a', '2ts', 1, 1, NULL, 'Patrística', 'Paulo, Silvano e Timóteo. Irineu de Lyon comenta que 2 Tessalonicenses esclarece questões sobre os últimos dias.', 'Irineu de Lyon', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('3c8a166e-dc48-4f5c-ae5f-aae45a2a3021', '1tm', 1, 1, NULL, 'Patrística', 'Paulo a Timóteo. Tertuliano comenta que 1 Timóteo trata da liderança na Igreja.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('b194382e-7da1-4a92-828b-cbc6a6ffbdad', '2tm', 1, 1, NULL, 'Patrística', 'Paulo a Timóteo. Orígenes comenta que 2 Timóteo é o testamento final de Paulo.', 'Orígenes', 'commentary', '#6B21A8', NOW());

COMMIT;

